############################################# ### Generated from PreTeXt source ### ### https://pretextbook.org ### ############################################# ## DBsubject() ## DBchapter() ## DBsection() ## Level() ## KEYWORDS() ## TitleText1() ## EditionText1() ## AuthorText1() ## Section1(not reported) ## Problem1(1.2.9.162) ## Author() ## Institution() ## Language(en-US)
DOCUMENT();
############################################################ # Load Macros ############################################################ loadMacros( "PGstandard.pl", "PGML.pl", "AnswerFormatHelp.pl", "PGcourse.pl", ); COMMENT('Authored in PreTeXt');
############################################################ # Header ############################################################ TEXT(beginproblem());
############################################################ # PG Setup Code ############################################################ Context('Numeric'); $girl = random(2,6,2); $boy = random(3,7,2); $factor = random(5,9,1); $totalgirls = Real($girl*$factor); $total = Real(($girl+$boy)*$factor);
############################################################ # Body ############################################################
BEGIN_PGML The ratio of girls to boys in a preschool is [$girl] to [$boy]. If there are [$total] kids in the school, how many girls are there in the preschool?
[_]{$totalgirls}{10}
END_PGML
############################################################ # Solution ############################################################
BEGIN_PGML_SOLUTION Let [`x`] be the number of girls in the preschool. We can represent this situation with the following proportion:
[`\frac{[$girl]}{[$girl]+[$boy]} = \frac{x}{[$total]}\text{.}`] Solve this equation for [`x\text{.}`]
END_PGML_SOLUTION
############################################################ # End Problem ############################################################
ENDDOCUMENT();
